SELECT m.*
FROM t_owners_assembly_package_material link
JOIN t_owners_assembly_material m ON m.material_id = link.material_id
WHERE link.package_id = #{packageId}
  AND link.tenant_id = #{tenantId}
  AND m.tenant_id = #{tenantId}
ORDER BY m.material_type ASC, m.material_id ASC

mapper.insert:
INSERT INTO t_owners_assembly_package_material (package_id, tenant_id, material_id)
SELECT #{packageId}, #{tenantId}, material_id
FROM t_owners_assembly_material
WHERE material_id = #{materialId}
  AND tenant_id = #{tenantId}
  AND session_id = (
      SELECT session_id
      FROM t_owners_assembly_package
      WHERE package_id = #{packageId}
        AND tenant_id = #{tenantId}
  )

