UPDATE t_owners_assembly_package
SET status = 'VOTING',
    update_time = CURRENT_TIMESTAMP
WHERE package_id = #{packageId}
  AND tenant_id = #{tenantId}
  AND status = 'PUBLIC_NOTICE'

UPDATE t_owners_assembly_package
SET status = 'SETTLED',
    update_time = CURRENT_TIMESTAMP
WHERE package_id = #{packageId}
  AND tenant_id = #{tenantId}
  AND status = 'VOTING'

