    SELECT 1
    FROM t_owners_assembly_delivery
    WHERE package_id = #{packageId}
      AND tenant_id = #{tenantId}
      AND opid = #{opid}
      AND uid = #{uid}
      AND delivery_channel = #{deliveryChannel}
)

