INSERT INTO t_owners_assembly_vote_record (
    package_id, subject_id, vote_id, tenant_id, opid, uid, vote_channel,
    package_hash, ballot_file_hash, signature_hash, valid_flag
) VALUES (
    #{packageId}, #{subjectId}, #{voteId}, #{tenantId}, #{opid}, #{uid}, #{voteChannel},
    #{packageHash}, #{ballotFileHash}, #{signatureHash}, #{validFlag}
)

mapper.select:
SELECT MIN(create_time)
FROM t_owners_assembly_vote_record
WHERE package_id = #{packageId}
  AND tenant_id = #{tenantId}
  AND uid = #{uid}
  AND valid_flag = 1

mapper.update:
UPDATE t_owners_assembly_vote_record
SET valid_flag = 0,
    invalidated_by_vote_id = #{invalidatedByVoteId},
    invalid_reason = #{invalidReason}
WHERE vote_id = #{voteId}
  AND valid_flag = 1

mapper.select:
SELECT NOT EXISTS (
    SELECT 1
    FROM t_owners_assembly_subject s
    LEFT JOIN t_voting_result r ON r.subject_id = s.subject_id
    WHERE s.package_id = #{packageId}
      AND s.tenant_id = #{tenantId}
      AND COALESCE(r.passed, 0) != 1
)
